      "keystrokes": "cat > compute_corners.py << 'EOF'
import numpy as np
import cdd

def count_corners(A, b, tol=1e-8):
    m, n = A.shape
    rows = []
    for i in range(m):
        rows.append([b[i]] + list(-A[i]))
    for i in range(n):
        row = [0.] * (n + 1)
        row[i + 1] = 1.0
        rows.append(row)
    arr = np.array(rows, dtype=np.float64)
    mat = cdd.matrix_from_array(arr, lin_set=range(m), rep_type=cdd.RepType.INEQUALITY)
    P = cdd.Polyhedron(mat)
    V = P.get_generators()
    vertices = []
    for i in range(V.row_size):
        row = V[i]
        if row[0] == 1:
            vertex = np.array(row[1:], dtype=np.float64)
            if (vertex >= -tol).all():
                vertices.append(vertex)
    uniq = set()
    for v in vertices:
        key = tuple(np.round(v, decimals=8))
        uniq.add(key)
    return len(uniq)

if __name__ == '__main__':
    counts = []
    i = 0
    while True:
        try:
            A = np.loadtxt(f'A_{i}.csv', delimiter=',')
            b = np.loadtxt(f'b_{i}.csv', delimiter=',')
        except FileNotFoundError:
            break
        A = A.reshape(6, 40)
        b = b.reshape(6)
        cnt = count_corners(A, b)
        counts.append(cnt)
        print(f'Iteration {i}: {cnt}')
        i += 1
    np.savetxt('/app/corner_counts.txt', counts, fmt='%d')
    print('Done.')
EOF
